const clientId = 'YOUR_CLIENT_ID';
const redirectUri = 'YOUR_REDIRECT_URI';
const authUrl = 'https://YOUR_AUTH_PROVIDER/authorize';
const apiUrl = 'https://YOUR_API_ENDPOINT';
let accessToken = null;

function authenticate() {
    const scope = 'YOUR_SCOPES';
    const responseType = 'token';
    const url = `${authUrl}?response_type=${responseType}&client_id=${clientId}&redirect_uri=${encodeURIComponent(redirectUri)}&scope=${encodeURIComponent(scope)}`;
    window.location.href = url;
}

function parseAccessToken() {
    const hash = window.location.hash;
    if (hash) {
        const params = new URLSearchParams(hash.substring(1));
        accessToken = params.get('access_token');
        sessionStorage.setItem('access_token', accessToken);
        window.location.hash = ''; // Clear the hash
    } else {
        accessToken = sessionStorage.getItem('access_token');
    }
}

function callApi(endpoint) {
    if (!accessToken) {
        console.error('Access token is missing.');
        return;
    }

    fetch(`${apiUrl}/${endpoint}`, {
        method: 'GET',
        headers: {
            'Authorization': `Bearer ${accessToken}`,
            'Content-Type': 'application/json'
        }
    })
    .then(response => {
        if (!response.ok) {
            throw new Error('API call failed: ' + response.statusText);
        }
        return response.json();
    })
    .then(data => {
        console.log('API Response:', data);
    })
    .catch(error => {
        console.error('Error:', error);
    });
}

